                suffix="COP" max={10} step={0.1}
                className="bg-white p-6 rounded-3xl shadow-sm"
              />
              <FlexibleNumberInput 
                label="Աղմուկի Մակարդակ (dB)" 
                value={formData.noiseLevel} 
