  return (
    <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 space-y-6 animate-in fade-in duration-300">
      <h5 className="font-black text-[11px] text-slate-700 uppercase tracking-widest flex items-center gap-2 border-b border-slate-50 pb-3">
         <Box size={14} className="text-blue-500" />
         {label} Մոդուլ (1-6)
      </h5>
      <div className="space-y-6 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">

        {/* Միավոր 1 */}
        <div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100 space-y-3">
          <label className="text-[12px] font-black text-blue-600 uppercase tracking-widest">1</label>
          <FlexibleNumberInput label="Քանակ" value={detail.outdoorCount} onChange={(val) => onValueChange(sys, 'outdoorCount', val)} max={100} />
          <FlexibleNumberInput label="Գին" value={detail.outdoorPrice} onChange={(val) => onValueChange(sys, 'outdoorPrice', val)} max={10000000} step={10000} suffix="֏" />
        </div>

        {/* Միավոր 2 */}
        <div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100 space-y-3">
          <label className="text-[12px] font-black text-indigo-600 uppercase tracking-widest">2</label>
          <FlexibleNumberInput label="Քանակ" value={detail.indoorCount} onChange={(val) => onValueChange(sys, 'indoorCount', val)} max={500} />
          <FlexibleNumberInput label="Գին" value={detail.indoorPrice} onChange={(val) => onValueChange(sys, 'indoorPrice', val)} max={5000000} step={5000} suffix="֏" />
        </div>

        {/* Միավոր 3 */}
        <div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100 space-y-3">
          <label className="text-[12px] font-black text-purple-600 uppercase tracking-widest">3</label>
          <FlexibleNumberInput label="Քանակ" value={detail.controllerCount} onChange={(val) => onValueChange(sys, 'controllerCount', val)} max={500} />
          <FlexibleNumberInput label="Գին" value={detail.controllerPrice} onChange={(val) => onValueChange(sys, 'controllerPrice', val)} max={1000000} step={1000} suffix="֏" />
        </div>

        {/* Միավոր 4 */}
        <div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100 space-y-3">
          <label className="text-[12px] font-black text-cyan-600 uppercase tracking-widest">4</label>
          <FlexibleNumberInput label="Քանակ" value={detail.componentCount} onChange={(val) => onValueChange(sys, 'componentCount', val)} max={500} />
          <FlexibleNumberInput label="Գին" value={detail.componentPrice} onChange={(val) => onValueChange(sys, 'componentPrice', val)} max={1000000} step={1000} suffix="֏" />
        </div>

        {/* Միավոր 5 */}
        <div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100 space-y-3">
          <label className="text-[12px] font-black text-emerald-600 uppercase tracking-widest">5</label>
          <FlexibleNumberInput label="Քանակ/մ" value={detail.materialCount} onChange={(val) => onValueChange(sys, 'materialCount', val)} max={1000} />
          <FlexibleNumberInput label="Գին" value={detail.materialPrice} onChange={(val) => onValueChange(sys, 'materialPrice', val)} max={1000000} step={500} suffix="֏" />
        </div>

        {/* Միավոր 6 */}
        <div className="p-4 bg-slate-50/50 rounded-2xl border border-slate-100 space-y-3">
          <label className="text-[12px] font-black text-orange-600 uppercase tracking-widest">6</label>
          <FlexibleNumberInput label="Քանակ" value={detail.miscCount} onChange={(val) => onValueChange(sys, 'miscCount', val)} max={1000} />
          <FlexibleNumberInput label="Գին" value={detail.miscPrice} onChange={(val) => onValueChange(sys, 'miscPrice', val)} max={5000000} step={1000} suffix="֏" />
