import React, { useState, useMemo } from 'react';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, Legend, Cell
} from 'recharts';
import { ProjectData } from '../types';
import { Plus, X, ArrowUpRight, Target, Activity, Filter, ChevronLeft, ChevronRight, MapPin } from 'lucide-react';
import InfoTooltip from './InfoTooltip';
import { BUILDING_TYPES } from './ProjectTable';

interface DashboardProps {
  projects: ProjectData[];
  onAddProject: (p: ProjectData) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ projects, onAddProject }) => {
  const [showQuickAdd, setShowQuickAdd] = useState(false);
  const [selectedType, setSelectedType] = useState<string>('Բոլորը');
  const [formData, setFormData] = useState({
    name: '', area: '', totalCost: '', buildingType: BUILDING_TYPES[0], distanceKm: '0'
  });

  const activeOnly = useMemo(() => projects.filter(p => p.isActive), [projects]);

  const filteredProjects = useMemo(() => {
    if (selectedType === 'Բոլորը') return activeOnly;
    return activeOnly.filter(p => p.buildingType === selectedType);
  }, [activeOnly, selectedType]);

  const sortedProjects = useMemo(() => 
    [...filteredProjects].sort((a, b) => Number(a.area) - Number(b.area)),
    [filteredProjects]
  );

  const stats = useMemo(() => {
    const count = filteredProjects.length;
    const totalArea = filteredProjects.reduce((acc, p) => acc + Number(p.area), 0);
    const totalRevenue = filteredProjects.reduce((acc, p) => acc + Number(p.totalCost), 0);

    const avgCostM2 = count > 0 
      ? (filteredProjects.reduce((acc, p) => acc + (Number(p.totalCost) / Number(p.area)), 0) / count)
      : 0;

    return { count, totalArea, avgCostM2, totalRevenue };
  }, [filteredProjects]);

  const costBreakdownData = useMemo(() => [
    { name: 'Սարքավորումներ', value: filteredProjects.reduce((acc, p) => acc + Number(p.equipmentCost), 0) },
    { name: 'Աշխատուժ', value: filteredProjects.reduce((acc, p) => acc + Number(p.laborCost), 0) },
    { name: 'Նյութեր', value: filteredProjects.reduce((acc, p) => acc + Number(p.materialsCost), 0) }
  ], [filteredProjects]);

  const COLORS = ['#1E293B', '#3B82F6', '#64748B'];

  const handleQuickSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = parseFloat(formData.totalCost);
    const area = parseFloat(formData.area);
    const dist = parseFloat(formData.distanceKm);
    const newProject: ProjectData = {
      id: Math.random().toString(36).substr(2, 9),
      name: formData.name,
      buildingType: formData.buildingType,
      area: area,
      height: 3,
      volume: area * 3,
      coolingLoad: 0,
      heatingLoad: 0,
      distanceKm: dist,
      systems: { split: false, multiSplit: false, vrv: false, chiller: false, boiler: false, ventilation: false },
      brandClass: 'mid',
      unitDetails: {
        split: { outdoorCount: 0, outdoorPrice: 0, indoorCount: 0, indoorPrice: 0, controllerCount: 0, controllerPrice: 0, componentCount: 0, componentPrice: 0, materialCount: 0, materialPrice: 0, miscCount: 0, miscPrice: 0 },
        multiSplit: { outdoorCount: 0, outdoorPrice: 0, indoorCount: 0, indoorPrice: 0, controllerCount: 0, controllerPrice: 0, componentCount: 0, componentPrice: 0, materialCount: 0, materialPrice: 0, miscCount: 0, miscPrice: 0 },
        vrv: { outdoorCount: 0, outdoorPrice: 0, indoorCount: 0, indoorPrice: 0, controllerCount: 0, controllerPrice: 0, componentCount: 0, componentPrice: 0, materialCount: 0, materialPrice: 0, miscCount: 0, miscPrice: 0 },
        chiller: { outdoorCount: 0, outdoorPrice: 0, indoorCount: 0, indoorPrice: 0, controllerCount: 0, controllerPrice: 0, componentCount: 0, componentPrice: 0, materialCount: 0, materialPrice: 0, miscCount: 0, miscPrice: 0 },
        boiler: { outdoorCount: 0, outdoorPrice: 0, indoorCount: 0, indoorPrice: 0, controllerCount: 0, controllerPrice: 0, componentCount: 0, componentPrice: 0, materialCount: 0, materialPrice: 0, miscCount: 0, miscPrice: 0 },
        ventilation: { outdoorCount: 0, outdoorPrice: 0, indoorCount: 0, indoorPrice: 0, controllerCount: 0, controllerPrice: 0, componentCount: 0, componentPrice: 0, materialCount: 0, materialPrice: 0, miscCount: 0, miscPrice: 0 }
      },
      vrvOutdoor: '-', vrvIndoor: '-', controls: '-', automation: '-', ventilation: '-', otherDevices: '-',
      totalCost: total,
      equipmentCost: total * 0.7,
      laborCost: total * 0.15,
      materialsCost: total * 0.15,
      date: new Date().toISOString().split('T')[0],
      isActive: true,
      profitMargin: 20,
      complexityLevel: 3,
      warrantyYears: 2,
      deliveryDays: 14
    };
    onAddProject(newProject);
    setFormData({ name: '', area: '', totalCost: '', buildingType: BUILDING_TYPES[0], distanceKm: '0' });
    setShowQuickAdd(false);
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-1000">
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { height: 8px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #fef3c7; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #92400e; border-radius: 10px; }
      `}</style>

      <header className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight uppercase">Գործառնական Ցուցանիշներ</h2>
          <p className="text-slate-400 font-bold uppercase tracking-[0.3em] text-[10px] mt-2">Professional HVAC Business Intelligence</p>
        </div>
        <button 
          onClick={() => setShowQuickAdd(!showQuickAdd)}
          className={`flex items-center gap-2 px-8 py-4 rounded-2xl transition-all font-black text-xs uppercase tracking-widest shadow-xl transform active:scale-95 ${showQuickAdd ? 'bg-orange-100 text-orange-900 border border-orange-200' : 'bg-[#0F172A] text-white hover:bg-blue-600'}`}
        >
          {showQuickAdd ? <X size={16} /> : <Plus size={16} />}
          {showQuickAdd ? 'Չեղարկել' : 'Ավելացնել Տվյալ'}
        </button>
      </header>

      {/* Building Type Filter */}
      <div className="bg-[#FFEDD5] p-1 rounded-3xl border border-orange-100 shadow-lg relative">
        <div className="flex items-center custom-scrollbar overflow-x-auto whitespace-nowrap py-1 px-2 gap-2">
          <div className="flex items-center gap-3 px-6 py-3 border-r border-orange-200 text-orange-900 shrink-0">
            <Filter size={16} />
            <span className="text-[11px] font-black uppercase tracking-widest">Դասակարգում</span>
          </div>
          <div className="flex gap-2">
            {['Բոլորը', ...BUILDING_TYPES].map((type) => (
              <button
                key={type}
                onClick={() => setSelectedType(type)}
                className={`px-6 py-3 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all duration-300 ${selectedType === type ? 'bg-[#2563EB] text-white shadow-xl scale-105' : 'text-orange-900/60 hover:text-orange-900 hover:bg-orange-50'}`}
              >
                {type}
              </button>
            ))}
          </div>
        </div>
      </div>

      {showQuickAdd && (
        <form onSubmit={handleQuickSubmit} className="bg-white p-10 rounded-[2.5rem] border border-blue-100 shadow-2xl animate-in slide-in-from-top duration-500 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-8">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Անվանում</label>
              <input required type="text" placeholder="Hilton Lobby" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-50 px-5 py-4 rounded-2xl border border-slate-100 focus:border-blue-500 outline-none font-bold shadow-inner" />
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Մակերես (Մ²)</label>
              <input required type="number" placeholder="0" value={formData.area} onChange={e => setFormData({...formData, area: e.target.value})} className="w-full bg-slate-50 px-5 py-4 rounded-2xl border border-slate-100 focus:border-blue-500 outline-none font-black text-lg" />
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Հեռավորություն (կմ)</label>
              <input required type="number" placeholder="0" value={formData.distanceKm} onChange={e => setFormData({...formData, distanceKm: e.target.value})} className="w-full bg-slate-50 px-5 py-4 rounded-2xl border border-slate-100 focus:border-orange-500 outline-none font-black text-lg text-orange-600" />
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Տիպ</label>
              <select value={formData.buildingType} onChange={e => setFormData({...formData, buildingType: e.target.value})} className="w-full bg-slate-50 px-5 py-4 rounded-2xl border border-slate-100 focus:border-blue-500 outline-none font-bold">
                {BUILDING_TYPES.map(type => <option key={type} value={type}>{type}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Ընդհանուր Արժեք (֏)</label>
              <input required type="number" placeholder="0" value={formData.totalCost} onChange={e => setFormData({...formData, totalCost: e.target.value})} className="w-full bg-slate-50 px-5 py-4 rounded-2xl border border-slate-100 focus:border-blue-500 outline-none font-black text-lg text-blue-600" />
            </div>
          </div>
          <button type="submit" className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black uppercase tracking-[0.3em] text-xs hover:bg-blue-700 transition shadow-2xl shadow-blue-500/30">Հաստատել և Պահպանել</button>
        </form>
      )}

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        {[
          { label: 'Իրականացված Նախագծեր', value: stats.count, icon: Target, color: '#2563EB' },
          { label: 'Ընդհանուր Մակերես', value: `${stats.totalArea.toLocaleString()} մ²`, icon: Activity, color: '#1E293B' },
          { label: 'Միջին Ինդեքս (1մ²)', value: `${stats.avgCostM2.toLocaleString(undefined, { maximumFractionDigits: 0 })} ֏`, icon: ArrowUpRight, color: '#2563EB' },
          { label: 'Համախառն Շրջանառություն', value: `${(stats.totalRevenue / 1000000).toFixed(1)}M ֏`, icon: Target, color: '#1E293B' },
        ].map((item, i) => (
          <div key={i} className="bg-[#FFEDD5] p-10 rounded-[3rem] border border-orange-100 shadow-[0_20px_40px_rgba(251,191,36,0.1)] hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 group">
            <div className="flex items-center justify-between mb-8">
              <p className="text-[11px] font-black text-orange-900/60 uppercase tracking-widest">{item.label}</p>
              <div className="p-2 bg-white/50 rounded-xl group-hover:scale-110 transition-transform">
                <item.icon style={{ color: item.color }} size={24} />
              </div>
            </div>
            <p className="text-5xl font-black text-slate-900 tracking-tighter drop-shadow-sm">{item.value}</p>
            <div className="mt-6 h-1 w-12 rounded-full" style={{ backgroundColor: item.color, opacity: 0.3 }}></div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl overflow-hidden">
          <div className="flex justify-between items-start mb-10">
            <div>
              <h3 className="text-sm font-black uppercase tracking-widest text-slate-900 border-l-4 border-blue-600 pl-5">Գնագոյացման Կորելացիա</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1 tracking-widest ml-5">Cost vs Area Analysis</p>
            </div>
            <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 px-4 py-2 rounded-xl border border-blue-100">{selectedType}</span>
          </div>
          <div className="h-96">
            {sortedProjects.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={sortedProjects}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F1F5F9" />
                  <XAxis dataKey="area" stroke="#94A3B8" fontSize={11} fontWeight="800" label={{ value: 'Մակերես', position: 'insideBottom', offset: -10, fontSize: 10, fontWeight: '900' }} />
                  <YAxis stroke="#94A3B8" fontSize={11} fontWeight="800" tickFormatter={(val) => `${(val / 1000000).toFixed(1)}M`} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 25px 50px -12px rgba(0,0,0,0.15)', fontWeight: '900', padding: '20px' }}
                    formatter={(value: any) => [`${value.toLocaleString()} ֏`, 'Արժեք']}
                  />
                  <Line type="monotone" dataKey="totalCost" stroke="#2563EB" strokeWidth={6} dot={{ r: 8, fill: '#2563EB', strokeWidth: 4, stroke: '#fff' }} activeDot={{ r: 12, fill: '#0F172A' }} />
                </LineChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-200 gap-5">
                <Activity size={64} />
                <p className="text-[12px] font-black uppercase tracking-[0.3em]">Տվյալներ չկան</p>
              </div>
            )}
          </div>
        </div>

        <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl overflow-hidden">
          <div className="flex justify-between items-start mb-10">
            <div>
              <h3 className="text-sm font-black uppercase tracking-widest text-slate-900 border-l-4 border-slate-900 pl-5">Ծախսերի Դիֆերենցում</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1 tracking-widest ml-5">Expense Category Breakdown</p>
            </div>
            <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest bg-slate-50 px-4 py-2 rounded-xl border border-slate-200">{selectedType}</span>
          </div>
          <div className="h-96">
            {filteredProjects.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={costBreakdownData} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#F1F5F9" />
                  <XAxis type="number" stroke="#94A3B8" fontSize={11} fontWeight="800" tickFormatter={(val) => `${(val / 1000000).toFixed(1)}M`} />
                  <YAxis dataKey="name" type="category" stroke="#94A3B8" fontSize={11} fontWeight="800" width={110} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }}
                    formatter={(val: any) => [`${val.toLocaleString()} ֏`, 'Ծախս']}
                  />
                  <Bar dataKey="value" radius={[0, 15, 15, 0]} barSize={50}>
                    {costBreakdownData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-200 gap-5">
                <Target size={64} />
                <p className="text-[12px] font-black uppercase tracking-[0.3em]">Տվյալներ չկան</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { EstimateResult, BrandClass, ComparisonDelta, SelectedSystems } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Zap, Snowflake, Flame, Ruler, CheckCircle2, Crown, Star, Shield, Box, FileText, TrendingUp, Info, Download, Save, FileJson, ArrowUp, ArrowDown, AlertTriangle, MapPin } from 'lucide-react';

interface EstimateDisplayProps {
  result: EstimateResult | null;
  onSaveToArchive?: (est: EstimateResult) => void;
}

const EstimateDisplay: React.FC<EstimateDisplayProps> = ({ result, onSaveToArchive }) => {
  if (!result) return null;

  const COLORS = ['#1E293B', '#3B82F6', '#94A3B8'];
  const breakdownData = [
    { name: 'Սարքավորումներ', value: result.realistic.equipment },
    { name: 'Տեղադրում', value: result.realistic.labor },
    { name: 'Նյութեր', value: result.realistic.materials }
  ];

  const handlePrint = () => window.print();

  const handleExportJson = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(result, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `${result.name || 'hvac_estimate'}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const getDiscrepancyHints = () => {
    if (!result.comparison) return [];
    const hints: string[] = [];
    const comp = result.comparison;
    const ref = comp.referenceProject;

    if (Math.abs(comp.areaDelta) > 5) {
      hints.push(`📐 Մակերեսը ${Math.abs(comp.areaDelta).toFixed(1)}% ${comp.areaDelta > 0 ? 'մեծ' : 'փոքր'} է հղման նախագծից (${ref.area} մ²)։`);
    }

    if (Math.abs(result.volume / (result.area || 1) - ref.height) > 0.1) {
      hints.push(`📏 Առաստաղի բարձրությունը տարբերվում է (Reference: ${ref.height}մ, Current: ${(result.volume / (result.area || 1)).toFixed(1)}մ)։`);
    }

    if (Math.abs(comp.coolingDelta) > 10) {
      hints.push(`❄️ Հովացման պահանջը ${Math.abs(comp.coolingDelta).toFixed(1)}% ${comp.coolingDelta > 0 ? 'ավելի' : 'պակաս'} է (Ref: ${ref.coolingLoad}kW)։`);
    }

    if (Math.abs(result.distanceKm - ref.distanceKm) > 10) {
      hints.push(`🚗 Հեռավորությունը փոխվել է (Ref: ${ref.distanceKm}կմ, Current: ${result.distanceKm}կմ)։ Սա ազդել է տեղադրման և լոգիստիկ ծախսերի վրա։`);
    }

    const powerDensity = result.coolingLoad / (result.area || 1);
    if (powerDensity > 0.18) {
      hints.push(`🚨 ԶԳՈՒՇԱՑՈՒՄ. Հզորության խտությունը (${(powerDensity * 1000).toFixed(0)}W/m²) շատ բարձր է։`);
    }

    return hints;
  };

  const hints = getDiscrepancyHints();

  const DeltaBadge = ({ label, value }: { label: string, value: number }) => {
    if (Math.abs(value) < 1) return null;
    const isPositive = value > 0;
    return (
      <div className={`flex items-center gap-2 px-3 py-2 rounded-xl border ${isPositive ? 'bg-orange-50 border-orange-100 text-orange-700' : 'bg-emerald-50 border-emerald-100 text-emerald-700'}`}>
        <span className="text-[9px] font-black uppercase tracking-tight">{label}</span>
        <div className="flex items-center font-bold text-xs">
          {isPositive ? <ArrowUp size={12} /> : <ArrowDown size={12} />}
          {Math.abs(value).toFixed(0)}%
        </div>
      </div>
    );
  };

  const BrandBadge = ({ type }: { type: BrandClass }) => {
    const config = {
      high: { label: 'Premium Class', icon: Crown, color: 'text-amber-600 bg-amber-50 border-amber-100' },
      mid: { label: 'Standard Class', icon: Star, color: 'text-blue-600 bg-blue-50 border-blue-100' },
      low: { label: 'Economic Class', icon: Shield, color: 'text-slate-600 bg-slate-50 border-slate-100' },
    };
    const { label, icon: Icon, color } = config[type];
    return (
      <span className={`${color} text-[9px] font-black px-3 py-1.5 rounded-lg uppercase tracking-widest flex items-center gap-1.5 border`}>
        <Icon size={12} />
        {label}
      </span>
    );
  };

  return (
    <div className="bg-white p-10 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.05)] border border-slate-100 space-y-10 animate-in fade-in duration-700 print-shadow-none">

      <div className="no-print flex flex-wrap gap-3 border-b border-slate-50 pb-8">
        <button onClick={() => onSaveToArchive?.(result)} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all shadow-lg shadow-blue-500/20">
          <Save size={16} /> Պահպանել Արխիվում
        </button>
        <button onClick={handlePrint} className="flex items-center gap-2 bg-slate-900 hover:bg-slate-800 text-white px-5 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all shadow-lg shadow-slate-900/20">
          <Download size={16} /> Արտահանել PDF
        </button>
        <button onClick={handleExportJson} className="flex items-center gap-2 bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 px-5 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">
          <FileJson size={16} /> Save JSON
        </button>
      </div>

      {result.comparison && (
        <div className="bg-slate-900 text-white p-8 rounded-2xl relative overflow-hidden space-y-6">
          <div className="absolute top-0 right-0 p-4 opacity-10">
            <TrendingUp size={100} />
          </div>
          <div className="relative z-10">
            <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-400 mb-4 flex items-center gap-2">
              <Zap size={14} /> Համեմատություն Արխիվի Հետ
            </h4>
            <p className="text-xs font-medium mb-6">
              Հաշվարկը հիմնված է <span className="font-black text-blue-400">"{result.comparison.referenceProjectName}"</span> նախագծի վրա:
            </p>
            <div className="flex flex-wrap gap-4">
              <DeltaBadge label="Մակերես" value={result.comparison.areaDelta} />
              <DeltaBadge label="Հովացում" value={result.comparison.coolingDelta} />
              <DeltaBadge label="Ջեռուցում" value={result.comparison.heatingDelta} />
            </div>

            {hints.length > 0 && (
              <div className="mt-8 pt-6 border-t border-white/10 space-y-3">
                <p className="text-[9px] font-black text-blue-400 uppercase tracking-widest flex items-center gap-2 mb-2">
                   <AlertTriangle size={12} /> Տեխնիկական Շեղումների Վերլուծություն
                </p>
                {hints.map((hint, i) => (
                  <div key={i} className="bg-white/5 border border-white/10 p-4 rounded-xl text-[11px] text-slate-300 font-medium leading-relaxed">
                    {hint}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      <div className="flex justify-between items-start">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <FileText className="text-blue-600" size={20} />
            <h3 className="text-2xl font-black text-slate-900 tracking-tight uppercase">{result.name || 'Project Draft'}</h3>
          </div>
          <div className="flex items-center gap-2">
            <BrandBadge type={result.brandClass} />
            <span className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">{result.buildingType}</span>
          </div>
        </div>
        <div className="text-right">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Հեռավորություն</p>
          <div className="flex items-center justify-end gap-1 text-xl font-black text-slate-900">
            <MapPin size={18} className="text-orange-500" />
            {result.distanceKm} <span className="text-xs text-slate-400">կմ</span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-blue-600 p-8 rounded-2xl text-white shadow-2xl relative overflow-hidden">
          <TrendingUp className="absolute top-4 right-4 text-white/20" size={60} />
          <p className="text-blue-100 text-[10px] font-black uppercase tracking-[0.2em] mb-2">Օպտիմալ Ինվեստիցիա</p>
          <p className="text-4xl font-black tracking-tighter">{result.realistic.total.toLocaleString()} <span className="text-lg font-bold opacity-40">֏</span></p>
        </div>
        <div className="bg-white border border-slate-200 p-8 rounded-2xl">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mb-2">Ռիսկային Սահման (+15%)</p>
          <p className="text-4xl font-black tracking-tighter text-slate-900">{result.conservative.total.toLocaleString()} <span className="text-lg font-bold opacity-40">֏</span></p>
        </div>
      </div>

      <div className="grid grid-cols-4 gap-6 bg-slate-50/50 p-6 rounded-2xl border border-slate-100">
        <div className="text-center">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Ծավալ</p>
          <p className="font-black text-slate-800">{result.volume} մ³</p>
        </div>
        <div className="text-center border-x border-slate-200">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Հովացում</p>
          <p className="font-black text-slate-800">{result.coolingLoad} kW</p>
        </div>
        <div className="text-center border-r border-slate-200">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Ջեռուցում</p>
          <p className="font-black text-slate-800">{result.heatingLoad} kW</p>
        </div>
        <div className="text-center">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Մակերես</p>
          <p className="font-black text-slate-800">{result.area} մ²</p>
        </div>
      </div>

      <div className="space-y-6 pt-6">
        <h4 className="text-[10px] font-black text-slate-900 uppercase tracking-[0.2em] text-center flex items-center justify-center gap-4">
          <div className="h-[1px] bg-slate-100 flex-1"></div> Ծախսերի Կառուցվածք <div className="h-[1px] bg-slate-100 flex-1"></div>
        </h4>
        <div className="h-64 no-print">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie data={breakdownData} innerRadius={80} outerRadius={100} paddingAngle={5} dataKey="value" animationDuration={1500}>
                {breakdownData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
              </Pie>
              <Tooltip formatter={(v: any) => `${v.toLocaleString()} ֏`} />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="hidden print:block pt-20">
        <div className="flex justify-between items-end border-t border-slate-200 pt-8">
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Պատրաստող՝</p>
            <div className="w-48 border-b border-slate-900 mt-8"></div>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ամսաթիվ՝</p>
            <p className="font-bold text-sm mt-4">{new Date().toLocaleDateString('hy-AM')}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EstimateDisplay;

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { Calculator as CalculatorIcon, Database as DatabaseIcon, LayoutDashboard, BrainCircuit, Download, Upload } from 'lucide-react';
import { ProjectData, EstimateResult, AiInsight, SelectedSystems, BrandClass, SystemUnits, ComparisonDelta } from './types';
import { INITIAL_PROJECTS, SAFETY_MARGIN } from './constants';
import Dashboard from './components/Dashboard';
import ProjectTable from './components/ProjectTable';
import EstimatorForm from './components/EstimatorForm';
import EstimateDisplay from './components/EstimateDisplay';
import { getAiAnalysis } from './services/geminiService';

const LOGISTICS_RATE_PER_KM = 800; // Յուրաքանչյուր կմ-ի հավելյալ ծախս (֏)

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'projects' | 'estimate'>('dashboard');
  const [projects, setProjects] = useState<ProjectData[]>(() => {
    const saved = localStorage.getItem('hvac_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });
  const [lastEstimate, setLastEstimate] = useState<EstimateResult | null>(null);
  const [projectDescription, setProjectDescription] = useState('');
  const [aiInsight, setAiInsight] = useState<AiInsight | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    localStorage.setItem('hvac_projects', JSON.stringify(projects));
  }, [projects]);

  const BRAND_WEIGHTS: Record<BrandClass, number> = { high: 1.25, mid: 1.0, low: 0.8 };

  const getSystemComplexity = (s: SelectedSystems): number => {
    let weight = 0;
    if (s.split) weight += 0.05;
    if (s.multiSplit) weight += 0.1;
    if (s.vrv) weight += 0.25;
    if (s.chiller) weight += 0.3;
    if (s.boiler) weight += 0.15;
    if (s.ventilation) weight += 0.2;
    return 1 + weight;
  };

  const calculateEstimate = useCallback((data: any) => {
    const area = data.area;
    const cooling = data.coolingLoad || 0;
    const heating = data.heatingLoad || 0;
    const distance = data.distanceKm || 0;
    const unitDetails = data.unitDetails;

    let totalUnitsCost = 0;
    Object.keys(data.systems).forEach((sysKey) => {
      const key = sysKey as keyof SelectedSystems;
      if (data.systems[key]) {
        const u = unitDetails[key] as SystemUnits;
        totalUnitsCost += (u.outdoorCount * u.outdoorPrice) + 
                         (u.indoorCount * u.indoorPrice) +
                         (u.controllerCount * u.controllerPrice) + 
                         (u.componentCount * u.componentPrice) + 
                         (u.materialCount * u.materialPrice) +
                         (u.miscCount * u.miscPrice);
      }
    });

    const manualEquip = parseFloat(data.equipmentCost) || 0;
    const manualLabor = parseFloat(data.laborCost) || 0;
    const manualMats = parseFloat(data.materialsCost) || 0;
    const finalEquipManual = totalUnitsCost + manualEquip;

    const logisticsCost = distance * LOGISTICS_RATE_PER_KM;

    let baseTotal: number, baseEquip: number, baseLabor: number, baseMats: number;
    let isMarketValueBased = false;
    let comparison: ComparisonDelta | undefined;

    if (finalEquipManual === 0) {
      const activeProjects = projects.filter(p => p.isActive);
      const similarProjects = activeProjects.filter(p => p.buildingType === data.buildingType);

      let baseReferencePricePerM2: number;

      if (similarProjects.length > 0) {
        // Ընտրում ենք այն նախագիծը, որի մակերեսը ամենամոտն է
        const bestMatch = similarProjects.reduce((prev, curr) => 
          Math.abs(curr.area - area) < Math.abs(prev.area - area) ? curr : prev
        );

        const normalizedCosts = similarProjects.map(p => {
          const pComplexity = getSystemComplexity(p.systems);
          const pBrandFactor = BRAND_WEIGHTS[p.brandClass];
          return (p.totalCost / p.area) / (pComplexity * pBrandFactor);
        });

        baseReferencePricePerM2 = normalizedCosts.reduce((a, b) => a + b, 0) / normalizedCosts.length;

        const currentComplexity = getSystemComplexity(data.systems);
        const currentBrandFactor = BRAND_WEIGHTS[data.brandClass as BrandClass];
        const currentPricePerM2 = baseReferencePricePerM2 * currentBrandFactor * currentComplexity;
        const refPricePerM2 = bestMatch.totalCost / (bestMatch.area || 1);

        comparison = {
          referenceProjectName: bestMatch.name,
          referenceProject: bestMatch,
          areaDelta: ((area - bestMatch.area) / (bestMatch.area || 1)) * 100,
          coolingDelta: bestMatch.coolingLoad > 0 ? ((cooling - bestMatch.coolingLoad) / bestMatch.coolingLoad) * 100 : 0,
          heatingDelta: bestMatch.heatingLoad > 0 ? ((heating - bestMatch.heatingLoad) / bestMatch.heatingLoad) * 100 : 0,
          pricePerM2Delta: ((currentPricePerM2 - refPricePerM2) / (refPricePerM2 || 1)) * 100
        };
      } else {
        baseReferencePricePerM2 = 38000; 
        isMarketValueBased = true;
      }

      const currentComplexity = getSystemComplexity(data.systems);
      const currentBrandFactor = BRAND_WEIGHTS[data.brandClass as BrandClass];
      const finalPricePerM2 = baseReferencePricePerM2 * currentBrandFactor * currentComplexity;

      baseTotal = (area * finalPricePerM2) + logisticsCost;

      const currentIntensity = cooling / (area || 1);
      if (currentIntensity > 0.15) {
        baseTotal *= (1 + (currentIntensity - 0.1) * 1.5);
      }

      baseEquip = baseTotal * 0.70;
      baseLabor = baseTotal * 0.18; 
      baseMats = baseTotal * 0.12;
    } else {
      baseEquip = finalEquipManual;
      baseLabor = (manualLabor > 0 ? manualLabor : baseEquip * 0.25) + logisticsCost;
      baseMats = manualMats > 0 ? manualMats : baseEquip * 0.15;
      baseTotal = baseEquip + baseLabor + baseMats;
    }

    const result: EstimateResult = {
      name: data.name,
      buildingType: data.buildingType,
      area: data.area,
      volume: data.area * data.height,
      coolingLoad: data.coolingLoad,
      heatingLoad: data.heatingLoad,
      distanceKm: distance,
      systems: data.systems,
      brandClass: data.brandClass,
      unitDetails: unitDetails,
      otherDevices: data.otherDevices || '',
      isMarketValueBased,
      comparison,
      realistic: {
        total: baseTotal,
        equipment: baseEquip,
        labor: baseLabor,
        materials: baseMats
      },
      conservative: {
        total: baseTotal * (1 + SAFETY_MARGIN),
        equipment: baseEquip * (1 + SAFETY_MARGIN),
        labor: baseLabor * (1 + SAFETY_MARGIN),
        materials: baseMats * (1 + SAFETY_MARGIN)
      },
      profitMargin: 20,
      complexityLevel: getSystemComplexity(data.systems) > 1.3 ? 4 : 2,
      warrantyYears: data.brandClass === 'high' ? 5 : 2,
      deliveryDays: 14
    };

    setLastEstimate(result);
    setProjectDescription(`Օբյեկտ՝ ${data.buildingType}, Մակերես՝ ${data.area}մ², Հեռավորություն՝ ${distance}կմ, Հովացում՝ ${data.coolingLoad}kW`);
    setAiInsight(null);
  }, [projects]);

  const saveToArchive = useCallback((est: EstimateResult) => {
    const newProject: ProjectData = {
      id: Math.random().toString(36).substr(2, 9),
      name: est.name || 'Նոր Հաշվարկ',
      buildingType: est.buildingType,
      area: est.area,
      height: est.volume / (est.area || 1),
      volume: est.volume,
      coolingLoad: est.coolingLoad,
      heatingLoad: est.heatingLoad,
      distanceKm: est.distanceKm,
      systems: est.systems,
      brandClass: est.brandClass,
      unitDetails: est.unitDetails,
      vrvOutdoor: '-', vrvIndoor: '-', controls: '-', automation: '-', ventilation: '-',
      otherDevices: est.otherDevices,
      equipmentCost: est.realistic.equipment,
      laborCost: est.realistic.labor,
      materialsCost: est.realistic.materials,
      totalCost: est.realistic.total,
      date: new Date().toISOString().split('T')[0],
      isActive: true,
      profitMargin: est.profitMargin ?? 20,
      complexityLevel: est.complexityLevel ?? 3,
      warrantyYears: est.warrantyYears ?? 2,
      deliveryDays: est.deliveryDays ?? 14
    };
    setProjects(prev => [...prev, newProject]);
    alert("Հաշվարկը պահպանվեց արխիվում:");
  }, []);

  const exportAllData = () => {
    const dataToSave = { projects, exportDate: new Date().toISOString() };
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(dataToSave, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `HVAC_Workspace_${new Date().toISOString().split('T')[0]}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const imported = JSON.parse(event.target?.result as string);
        const data = imported.projects || imported;
        if (Array.isArray(data)) {
          setProjects(data);
          alert("Տվյալները ներմուծվեցին:");
        }
      } catch (err) { alert("Սխալ ֆայլի ձևաչափ:"); }
    };
    reader.readAsText(file);
  };

  const handleGenerateAi = async () => {
    if (!lastEstimate) return;
    setIsAiLoading(true);
    try {
      const insights = await getAiAnalysis(lastEstimate, projects, projectDescription);
      setAiInsight(insights);
    } catch (error) { console.error("AI error:", error); }
    finally { setIsAiLoading(false); }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#F1F5F9] font-sans text-slate-900">
      <div className="flex flex-1 overflow-hidden">
        <aside className="w-72 bg-[#0F172A] text-white flex-shrink-0 flex flex-col z-20 shadow-[4px_0_24px_rgba(0,0,0,0.1)] no-print">
          <div className="p-8 mb-4">
            <h1 className="text-xl font-black flex items-center gap-3 tracking-tighter uppercase">
              <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-500/20">
                <CalculatorIcon className="text-white" size={20} />
              </div>
              <div className="flex flex-col leading-none">
                <span className="text-white">HVAC</span>
